definition.script:
pipeline {
    agent any
    environment {
        ARGOCD_DIR = "/var/jenkins_home"  // Carpeta montada con tus scripts
    }
    stages {
        stage('Preparar scripts') {
            steps {
                echo "🔧 Ajustando permisos de los scripts"
                sh "chmod +x ${ARGOCD_DIR}/*.sh"
            }
        }
        stage('Ejecutar setup-full.sh') {
            steps {
                echo "🚀 Ejecutando setup-full.sh"
                sh """
                cd ${ARGOCD_DIR}
                ./setup-full.sh argocd flask-app
                """
            }
        }
    }
    post {
        always {
            echo "✅ Pipeline finalizado"
        }
    }
}
